(function(w){"use strict";
function e(v){return String(v==null?"":v).replace(/[&<>"']/g,function(c){return {"&":"&amp;","<":"&lt;",">":"&gt;","\"":"&quot;","'":"&#39;"}[c]||c;});}
function renderField(f){var a=' data-key="'+e(f.key)+'"';if(f.raw)a+=' data-raw="1"';if(f.type==='select'){return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><select class="hm-calc-select"'+a+'>'+f.options.map(function(o){return '<option value="'+e(o[0])+'"'+(String(o[0])===String(f.default)?' selected':'')+'>'+e(o[1])+'</option>';}).join('')+'</select></div>';}if(f.type==='textarea'){return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><textarea class="hm-calc-input" rows="4"'+a+' placeholder="'+e(f.placeholder||'')+'">'+e(f.default||'')+'</textarea></div>';}var type=f.type==='date'?'date':'text';var mode=f.type==='integer'?'numeric':'decimal';return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><input class="hm-calc-input" type="'+type+'" inputmode="'+mode+'"'+a+' placeholder="'+e(f.placeholder||'')+'" value="'+e(f.default||'')+'"></div>';}
function makeRender(def){return function(root,api){var html='<div class="hm-calc-panel"><div class="hm-calc-form">';if(def.hint)html+='<p class="hm-calc-hint">'+e(def.hint)+'</p>';html+='<div class="hm-calc-grid-2">'+def.fields.map(renderField).join('')+'</div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">계산하기</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>';root.innerHTML=html;var els=Array.prototype.slice.call(root.querySelectorAll('[data-key]')),go=root.querySelector('button'),msg=root.querySelector('.hm-calc-message'),res=root.querySelector('.hm-calc-result');go.addEventListener('click',function(){var x={};els.forEach(function(el){var k=el.getAttribute('data-key');if(el.tagName==='SELECT'||el.getAttribute('data-raw')==='1'||el.type==='date')x[k]=el.value;else x[k]=api.parseNumber(el.value);});var r=def.compute(x);if(r&&r.error){api.setMessage(msg,r.error);api.clearResult(res);return;}api.setMessage(msg,'');api.setResult(res,def.format(r,api));});};}
var defs=[{id:"garden-soil-volume",fields:[{"key":"lengthM","label":"화단 길이 (m)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"widthM","label":"화단 너비 (m)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"depthCm","label":"흙 깊이 (cm)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"bagLiters","label":"흙 한 포대 용량 (L)","type":"number","placeholder":"","default":"20","options":[],"raw":false}],hint:"다짐과 흘림을 고려하면 계산값보다 5~15% 여유 있게 준비하세요.",compute:function(x){var l=Number(x.lengthM),w=Number(x.widthM),d=Number(x.depthCm),b=Number(x.bagLiters);if(![l,w,d,b].every(Number.isFinite)||l<0||w<0||d<0||b<=0)return{error:"길이·너비·깊이는 0 이상, 포대 용량은 0보다 크게 입력해 주세요."};var m3=l*w*d/100,liters=m3*1000;return{cubicMeters:m3,liters:liters,bags:Math.ceil(liters/b)};},format:function(r,api){return api.resultCard("필요 흙 부피",api.formatNumber(r.cubicMeters,3)+"m³",api.formatNumber(r.liters,1)+"L")+api.resultCard("필요 포대 수",api.formatNumber(r.bags,0)+"포","올림 계산");}},{id:"mulch-bags-needed",fields:[{"key":"areaM2","label":"시공 면적 (m²)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"depthCm","label":"덮는 두께 (cm)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"bagLiters","label":"한 포대 용량 (L)","type":"number","placeholder":"","default":"50","options":[],"raw":false}],hint:"",compute:function(x){var a=Number(x.areaM2),d=Number(x.depthCm),b=Number(x.bagLiters);if(![a,d,b].every(Number.isFinite)||a<0||d<0||b<=0)return{error:"면적과 두께는 0 이상, 포대 용량은 0보다 크게 입력해 주세요."};var m3=a*d/100,liters=m3*1000;return{cubicMeters:m3,liters:liters,bags:Math.ceil(liters/b)};},format:function(r,api){return api.resultCard("필요 부피",api.formatNumber(r.cubicMeters,3)+"m³",api.formatNumber(r.liters,1)+"L")+api.resultCard("필요 포대 수",api.formatNumber(r.bags,0)+"포","올림 계산");}},{id:"lawn-seed-amount",fields:[{"key":"areaM2","label":"파종 면적 (m²)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"rateGramM2","label":"권장 파종량 (g/m²)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"bagKg","label":"제품 한 포장 (kg)","type":"number","placeholder":"","default":"1","options":[],"raw":false}],hint:"잔디 품종과 토양 상태에 맞는 제품 권장 파종량을 입력하세요.",compute:function(x){var a=Number(x.areaM2),r=Number(x.rateGramM2),b=Number(x.bagKg);if(![a,r,b].every(Number.isFinite)||a<0||r<0||b<=0)return{error:"면적과 파종량은 0 이상, 포장 용량은 0보다 크게 입력해 주세요."};var g=a*r,kg=g/1000;return{grams:g,kilograms:kg,bags:Math.ceil(kg/b)};},format:function(r,api){return api.resultCard("필요 씨앗",api.formatNumber(r.kilograms,3)+"kg",api.formatNumber(r.grams,1)+"g")+api.resultCard("필요 포장 수",api.formatNumber(r.bags,0)+"개","올림 계산");}},{id:"irrigation-runtime",fields:[{"key":"areaM2","label":"급수 면적 (m²)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"targetMm","label":"목표 급수량 (mm)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"flowLpm","label":"분당 유량 (L/min)","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"1mm의 물이 1m²에 내리면 약 1L입니다.",compute:function(x){var a=Number(x.areaM2),m=Number(x.targetMm),f=Number(x.flowLpm);if(![a,m,f].every(Number.isFinite)||a<0||m<0||f<=0)return{error:"면적과 급수량은 0 이상, 유량은 0보다 크게 입력해 주세요."};var liters=a*m,minutes=liters/f;return{liters:liters,minutes:minutes,hours:minutes/60};},format:function(r,api){return api.resultCard("필요 물의 양",api.formatNumber(r.liters,1)+"L","")+api.resultCard("예상 관수시간",api.formatNumber(r.minutes,1)+"분",api.formatNumber(r.hours,2)+"시간");}},{id:"rainwater-harvest",fields:[{"key":"roofAreaM2","label":"지붕 수평 투영면적 (m²)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"rainfallMm","label":"강우량 (mm)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"efficiency","label":"수집 효율 (%)","type":"number","placeholder":"","default":"80","options":[],"raw":false}],hint:"초기 빗물 배제, 넘침, 증발 등의 손실을 효율 값에 반영하세요.",compute:function(x){var a=Number(x.roofAreaM2),m=Number(x.rainfallMm),e=Number(x.efficiency)/100;if(![a,m,e].every(Number.isFinite)||a<0||m<0||e<0||e>1)return{error:"면적과 강우량은 0 이상, 효율은 0~100%로 입력해 주세요."};var gross=a*m,collected=gross*e;return{grossLiters:gross,collectedLiters:collected,cubicMeters:collected/1000};},format:function(r,api){return api.resultCard("예상 수집량",api.formatNumber(r.collectedLiters,1)+"L",api.formatNumber(r.cubicMeters,3)+"m³")+api.resultCard("이론상 최대량",api.formatNumber(r.grossLiters,1)+"L","");}},{id:"pool-fill-time",fields:[{"key":"lengthM","label":"가로 (m)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"widthM","label":"세로 (m)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"averageDepthM","label":"평균 깊이 (m)","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"fillPercent","label":"채움 비율 (%)","type":"number","placeholder":"","default":"100","options":[],"raw":false},{"key":"flowLpm","label":"급수 유량 (L/min)","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"",compute:function(x){var l=Number(x.lengthM),w=Number(x.widthM),d=Number(x.averageDepthM),p=Number(x.fillPercent)/100,f=Number(x.flowLpm);if(![l,w,d,p,f].every(Number.isFinite)||l<0||w<0||d<0||p<0||p>1||f<=0)return{error:"크기는 0 이상, 채움 비율은 0~100%, 유량은 0보다 크게 입력해 주세요."};var m3=l*w*d*p,liters=m3*1000,minutes=liters/f;return{cubicMeters:m3,liters:liters,minutes:minutes,hours:minutes/60};},format:function(r,api){return api.resultCard("필요 물의 양",api.formatNumber(r.cubicMeters,3)+"m³",api.formatNumber(r.liters,1)+"L")+api.resultCard("예상 소요시간",api.formatNumber(r.hours,2)+"시간",api.formatNumber(r.minutes,1)+"분");}}];defs.forEach(function(def){w.HM_CALC.register(def.id,{compute:def.compute,render:makeRender(def)});});})(window);
